<template><section class="page"><RouterLink to="/prompts">← {{t('promptops.detail.back')}}</RouterLink><div v-if="loading" class="state">{{t('promptops.common.loading')}}</div><div v-else-if="!prompt" class="state">{{t('promptops.detail.notFound')}}</div><template v-else><header><div><h2>{{prompt.name}}</h2><p>{{prompt.description}}</p></div><div class="actions"><RouterLink v-if="prompt.status!=='archived'" :to="`/prompts/${prompt.id}/edit`">{{t('promptops.actions.edit')}}</RouterLink><RouterLink :to="`/prompts/${prompt.id}/versions`">{{t('promptops.version.history')}}</RouterLink><button @click="openPlayground">{{t('promptops.detail.openPlayground')}}</button><button @click="duplicate">{{t('promptops.actions.duplicate')}}</button><button v-if="prompt.status==='archived'" @click="restorePrompt">{{t('promptops.editor.restorePrompt')}}</button><button v-else class="danger" @click="archivePrompt">{{t('promptops.actions.archive')}}</button></div></header><div class="summary"><article><small>{{t('promptops.table.status')}}</small><strong>{{t(`promptops.status.${prompt.status}`)}}</strong></article><article><small>{{t('promptops.table.version')}}</small><strong>{{prompt.currentVersion}}</strong></article><article><small>{{t('promptops.version.versions')}}</small><strong>{{versions.length}}</strong></article><article><small>{{t('promptops.table.owner')}}</small><strong>{{prompt.owner.name}}</strong></article></div><article class="card"><h3>{{t('promptops.table.scenario')}}</h3><p>{{prompt.businessScenario}}</p></article><div class="grid"><article class="card"><h3>System Prompt</h3><pre>{{prompt.systemPrompt||'—'}}</pre></article><article class="card"><h3>User Prompt</h3><pre>{{prompt.userPrompt||'—'}}</pre></article></div><article class="card"><h3>{{t('promptops.detail.variables')}}</h3><p v-if="!prompt.variables.length">—</p><div v-for="variable in prompt.variables" :key="variable.id" class="variable"><code>&#123;&#123;{{variable.name}}&#125;&#125;</code><span>{{variable.displayName}} · {{variable.type}} · {{variable.required?t('promptops.detail.required'):t('promptops.detail.optional')}}</span></div></article><article class="card"><h3>{{t('promptops.detail.modelConfig')}}</h3><dl><dt>{{t('promptops.table.model')}}</dt><dd>{{prompt.modelProvider}} / {{prompt.modelName}}</dd><dt>Temperature</dt><dd>{{prompt.temperature}}</dd><dt>Max Tokens</dt><dd>{{prompt.maxTokens}}</dd><dt>{{t('promptops.editor.outputType')}}</dt><dd>{{prompt.outputType}}</dd><dt>{{t('promptops.editor.expectedOutput')}}</dt><dd>{{prompt.expectedOutputFormat||'—'}}</dd><dt>{{t('promptops.table.updatedAt')}}</dt><dd>{{prompt.updatedAt}}</dd></dl></article></template></section></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{RouterLink,useRoute,useRouter}from'vue-router';import{useI18n}from'vue-i18n';import type{PromptOpsPrompt as Prompt,PromptOpsPromptVersion as PromptVersion}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';import{PromptPlaygroundBridge}from'../../services/prompt-playground-bridge';const{t}=useI18n(),route=useRoute(),router=useRouter(),services=usePromptOpsServices();const prompt=ref<Prompt>(),versions=ref<PromptVersion[]>([]),loading=ref(true);const load=async()=>{const id=String(route.params.id);[prompt.value,versions.value]=await Promise.all([services.promptRepository.getById(id),services.promptVersionRepository.listByPromptId(id)]);loading.value=false};onMounted(load);const archivePrompt=async()=>{if(prompt.value&&window.confirm(t('promptops.library.archiveConfirm',{name:prompt.value.name}))){await services.promptRepository.archive(prompt.value.id);await load()}};const restorePrompt=async()=>{if(prompt.value)prompt.value=await services.promptEditorService.restorePrompt(prompt.value.id)};const duplicate=async()=>{if(prompt.value){const copy=await services.promptEditorService.duplicate(prompt.value.id);await router.push(`/prompts/${copy.id}`)}};const openPlayground=async()=>{if(prompt.value){PromptPlaygroundBridge.save(prompt.value);await router.push(`/playground/${prompt.value.id}`)}};</script>
<style scoped>.page{display:grid;gap:17px}.page>a,.actions a{color:#2563eb;text-decoration:none}header,.actions{display:flex;justify-content:space-between;gap:9px;align-items:flex-start;flex-wrap:wrap}header h2{margin:0}.actions a,.actions button{padding:8px 10px;border:1px solid #d1d5db;border-radius:7px;background:var(--n-color,#fff);color:inherit}.actions .danger{color:#b91c1c}.summary{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.summary article,.card{padding:16px;border:1px solid #e5e7eb;border-radius:10px;background:var(--n-color,#fff)}.summary small,.summary strong{display:block}.summary small{color:#64748b;margin-bottom:7px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.card pre{white-space:pre-wrap;font:inherit}.variable{display:flex;gap:16px;padding:8px 0;border-bottom:1px solid #e5e7eb}dl{display:grid;grid-template-columns:160px 1fr;gap:8px}dt{color:#64748b}.state{text-align:center;padding:55px}@media(max-width:800px){.summary,.grid{grid-template-columns:1fr}}</style>
